-- 0020_seed_proveedor_illume.sql
--
-- Alta manual del proveedor Illume (iluminacion LED automotriz y faros off-road) y su catalogo.
-- El proveedor NO se registro: `user_id` queda en NULL a proposito. El dueno se enlaza despues:
--     update public.providers set user_id = '<uuid>' where name = 'Illume';
--
-- Fuente del catalogo: https://illume.com.mx (Shopify, illume-com-mx.myshopify.com),
-- endpoint publico /products.json -> 82 productos, todos con imagen.
-- Se descarto MercadoLibre como fuente: solo expone 21 productos sin imagenes y el listado
-- completo esta detras de verificacion de cuenta.
--
-- Criterios aplicados:
--   * `active` refleja disponibilidad real en la tienda (58 activos / 24 inactivos), no true fijo.
--   * `stock` queda NULL: products.json publico expone `available` (booleano), no cantidad.
--   * El producto con precio 0 entra con active = false.
--   * `image_url` / `external_url` son URLs remotas; no se descargan assets.
--
-- Todo el archivo es idempotente: re-aplicarlo no duplica ni el proveedor ni los productos.

-- 1. Proveedor -----------------------------------------------------------------------------
-- `providers` no tiene unique sobre `name`, asi que la idempotencia se garantiza con NOT EXISTS
-- (un `on conflict do nothing` insertaria un duplicado en la segunda pasada).
insert into public.providers
  (name, type, estado, status, user_id, state, city, description, phone, website, logo_url, specialty)
select
  'Illume',
  'equipo',
  'activo',
  'aprobado',
  null,                       -- sin dueno: se enlaza despues
  'PENDIENTE',                -- la tienda no publica estado
  'PENDIENTE',                -- la tienda no publica ciudad
  'Iluminacion LED automotriz: kits de faros, barras de luz, lupas proyector y faros auxiliares off-road (linea Mammoth).',
  'PENDIENTE',                -- la tienda no publica telefono (/pages/contacto devuelve 404)
  'https://illume.com.mx',
  'https://illume.com.mx/cdn/shop/files/illume_logo_1200x1200.webp',
  array['iluminacion', 'faros LED', 'barras LED', 'off-road']
where not exists (
  select 1 from public.providers where name = 'Illume'
);

-- 2. Catalogo (82 productos) ---------------------------------------------------------------
insert into public.provider_products
  (provider_id, source_id, name, description, price, currency,
   image_url, external_url, source_platform, category, stock, active)
select
  p.id, v.source_id, v.name, v.description, v.price, 'MXN',
  v.image_url, v.external_url, 'web', v.category, null, v.active
from (values
