  ('7235569909834', 'Single Row Bar 20"', 'Presentamos nuestra barra Single Row Bar 20", un producto de calidad, diseñado para ofrecer una iluminación duradera y resistente en tus aventuras 4x4. Esta barra es compatible con el conector Plug&Play y cuenta con una aleación de aluminio de alto grado para asegurar un rendimiento de primera clase. Además, el producto cuenta con una certificación IP68, lo que lo hace resistente al agua y a la po', 2127, 'https://cdn.shopify.com/s/files/1/0561/4727/9946/files/1_5cbdcad6-c4f4-460a-8a15-3ac3f7f4fe56.jpg', 'https://illume.com.mx/products/single-row-bar-20', 'Barras LED', false),
  ('7235565977674', 'Round Light Amber', 'Disfruta sus aventuras 4x4 con los faros redondos de luz ámbar. Están certificados IP68 y son resistentes al agua y al polvo para que los acompañen por mucho tiempo. Duran hasta 50,000 horas para ofrecerte la luz adecuada en todas tus aventuras.', 1897, 'https://cdn.shopify.com/s/files/1/0561/4727/9946/files/1_a499bc8e-3c25-4cd1-a223-785e84450837.jpg', 'https://illume.com.mx/products/round-light-amber', 'Faros auxiliares', true),
  ('7235564339274', 'Round Light', 'Disfruta tus aventuras al aire libre con nuestra luz redonda. Está hecho de aleación de aluminio de grado alto y resistente a golpes y rayos, por lo que puedes contar con su durabilidad. La vida de la luz es hasta 50,000 horas, además es certificada IP68. Perfecta para tus necesidades 4x4.', 1897, 'https://cdn.shopify.com/s/files/1/0561/4727/9946/files/1_4c6824a4-ee2c-4f82-979f-467d6016c0ac.jpg', 'https://illume.com.mx/products/round-light', 'Faros auxiliares', true),
  ('7235561947210', 'Round Dot Headlight', 'Nuestro faro redondo Dot es una excelente opción para todos tus vehículos. Está equipado con IP68 a prueba de golpes y agua, además de resistencia al calor. La lente de cristal policarbonato ofrece resistencia a los impactos y la pintura electrostática es resistente a los rayos UV para mantener el color.', 1219, 'https://cdn.shopify.com/s/files/1/0561/4727/9946/files/1_efea005d-8e68-42f5-9205-94e29fa6b87f.jpg', 'https://illume.com.mx/products/round-dot-headlight', 'Faros principales', true),
  ('7235560570954', 'Quad Driving Amber Cover', 'Disfruta de la conducción con tu Quad Drive con nuestra cubierta Ambar. Esta funda ofrece protección total al Quad Drive con resistencia al desgaste y a los impactos. Añade un toque de color a tu dispositivo con estilo.', 391, 'https://cdn.shopify.com/s/files/1/0561/4727/9946/files/3_e1aabada-2c87-4b45-ac7b-0b77208dc820.jpg', 'https://illume.com.mx/products/quad-driving-amber-cover', 'Micas y cubiertas', false),
  ('7235559161930', 'Quad Dot Headlight', 'El faro Quad Dot trae una luz súper brillante para mejorar tu visibilidad y seguridad al volante. Hecho de una aleación de aluminio de alta calidad y con una clasificación IP86, este faro resiste los golpes y el agua. Y con una vida útil de 50,000 horas, el Quad Dot siempre brilla alto. El conector Plug & Play sumergible hace que la instalación sea fácil e instantánea.', 1219, 'https://cdn.shopify.com/s/files/1/0561/4727/9946/files/2_caaefbc4-f1ff-4d9d-81e7-f41787a886da.jpg', 'https://illume.com.mx/products/quad-dot-headlight', 'Faros principales', true),
  ('7235557130314', 'Dually Amber Cover', 'Nuestro Dually Amber Cover ofrece la protección necesaria para tu aventura. El plástico de alta resistencia en color ámbar proporciona una apariencia atractiva que se resiste a los elementos. La mejor protección para tu dually, sin importar dónde estés.', 63, 'https://cdn.shopify.com/s/files/1/0561/4727/9946/files/3_b2e2e84b-30f0-466d-ab00-16d67fdf78df.jpg', 'https://illume.com.mx/products/dually-amber-cover', 'Micas y cubiertas', false),
  ('7233091764298', 'Universal Switch 8', 'Universal Switch 8 es una botonera de iluminación versátil con 8 botones. Estos botones permiten controlar hasta 8 dispositivos electrónicos con una sola unidad, lo que le da la flexibilidad de controlar dispositivos independientes. El switch universal es resistente y de fácil uso,', 4234, 'https://cdn.shopify.com/s/files/1/0561/4727/9946/files/1_711ad9a7-f8c1-4cf6-b089-728e2ae37e79.jpg', 'https://illume.com.mx/products/universal-switch-8', 'Arneses y cableado', true),
  ('7233090519114', 'Dually Protector', 'El Dually Protector es el ideal para proteger sus luces duallys. Hecho con material resistente, le ofrece mayor protección para prolongar la vida de sus luces. ¡Mantén a salvo y haste destacar!', 63, 'https://cdn.shopify.com/s/files/1/0561/4727/9946/files/3_b03bc87c-fb63-487f-9262-fa464cad3339.jpg', 'https://illume.com.mx/products/dually-protector', 'Micas y cubiertas', false),
  ('7233052246090', 'Focos Led Illume Exclusive 90W', 'Nuestro foco LED Illume Exclusive de 90W es el foco de mayor potencia del mercado. Está diseñado con luces LED de calidad superior para ofrecer una luz brillante y eficiente. Esto garantiza un uso de larga duración.', 1399, 'https://cdn.shopify.com/s/files/1/0561/4727/9946/files/Exclusive90watts.jpg', 'https://illume.com.mx/products/focos-led-illume-exclusive-90w', 'Kits LED', true),
  ('7167320358986', 'Driving Laser Combo', 'Voltaje: 9-24V Corriente: 0,4 - 5,5 ± 0,1 A Temperatura. Color: 6000k ± 500 Potencia: 20-320W Lúmenes: Lúmenes altos CHIP: SMD Vida útil: 50.000 horas', 4800, 'https://cdn.shopify.com/s/files/1/0561/4727/9946/files/1_609fe744-0cf3-41a4-9ed7-bec11e67a9fa.jpg', 'https://illume.com.mx/products/driving-laser-combo', 'Faros off-road Mammoth', false),
  ('7063280549962', 'X Round Light Illume', 'Corriente: 0.4 - 5.5 ± 0.1 A Temp. Color: 6000k ± 500 Potencia: 20-320W Lumen: High Lumen CHIP: SMD Vida útil: 50,000 hrs', 1269, 'https://cdn.shopify.com/s/files/1/0561/4727/9946/products/xroundlightjpg1.jpg', 'https://illume.com.mx/products/x-round-light-illume', 'Faros off-road Mammoth', false),
  ('7063280287818', 'Mini Lens Illume', 'Corriente: 0.4 - 5.5 ± 0.1 A Temp. Color: 6000k ± 500 Potencia: 20-320W Lumen: High Lumen CHIP: SMD Vida útil: 50,000 hrs', 639, 'https://cdn.shopify.com/s/files/1/0561/4727/9946/products/minilensjpg1.jpg', 'https://illume.com.mx/products/mini-lens-illume', 'Faros off-road Mammoth', false),
  ('7063280091210', 'Duallys Laser Illume', 'Corriente: 0.4 - 5.5 ± 0.1 A Temp. Color: 6000k ± 500 Potencia: 20-320W Lumen: High Lumen CHIP: SMD Vida útil: 50,000 hrs', 793, 'https://cdn.shopify.com/s/files/1/0561/4727/9946/products/duallylaserjpg1.jpg', 'https://illume.com.mx/products/duallys-laser-illume', 'Faros off-road Mammoth', false),
