  ('7063271342154', 'Quad Driving Light Illume', 'Voltaje: 9-24V Corriente: 0.4 - 5.5 ± 0.1 A Temp. Color: 6000k ± 500 Potencia: 20-320W Lumen: High Lumen CHIP: SMD Vida útil: 50,000 hrs', 22357, 'https://cdn.shopify.com/s/files/1/0561/4727/9946/products/quaddrivinglightjpg1.jpg', 'https://illume.com.mx/products/quad-driving-light-illume', 'Faros off-road Mammoth', false),
  ('7063271014474', 'Driving Light Combo', 'Voltaje: 9-24V Corriente: 0.4 - 5.5 ± 0.1 A Temp. Color: 6000k ± 500 Potencia: 20-320W Lumen: High Lumen CHIP: SMD Vida útil: 50,000 hrs', 2357, 'https://cdn.shopify.com/s/files/1/0561/4727/9946/products/drivinglightcombo1jpg.jpg', 'https://illume.com.mx/products/driving-light-combo', 'Faros off-road Mammoth', true),
  ('7063269802058', 'Single Row Bar 6" Illume', 'Voltaje: 9-24V Corriente: 0.4 - 5.5 ± 0.1 A Temp. Color: 6000k ± 500 Potencia: 20-320W Lumen: High Lumen CHIP: SMD Vida útil: 50,000 hrs', 1432, 'https://cdn.shopify.com/s/files/1/0561/4727/9946/products/Singlerowbar6jpg1.jpg', 'https://illume.com.mx/products/single-row-bar-6-pulgadas', 'Faros off-road Mammoth', true),
  ('7063269507146', 'Single Row Bar 10" Illume', 'Voltaje: 9-24V Corriente: 0.4 - 5.5 ± 0.1 A Temp. Color: 6000k ± 500 Potencia: 20-320W Lumen: High Lumen CHIP: SMD Vida útil: 50,000 hrs', 1794, 'https://cdn.shopify.com/s/files/1/0561/4727/9946/products/Singlerowbar10jpg1.jpg', 'https://illume.com.mx/products/single-row-bar-10-pulgadas', 'Faros off-road Mammoth', true),
  ('6916446519370', 'Aux Interior y Exterior', null, 49, 'https://cdn.shopify.com/s/files/1/0561/4727/9946/products/T10360.jpg', 'https://illume.com.mx/products/aux-interior-y-exterior', 'Faros auxiliares', true),
  ('6916445306954', 'Faros y Calaveras', null, 190, 'https://cdn.shopify.com/s/files/1/0561/4727/9946/products/1156AMB.jpg', 'https://illume.com.mx/products/faros-y-calaveras', 'Faros auxiliares', true),
  ('6916444586058', 'Auxiliares interiores', null, 95, 'https://cdn.shopify.com/s/files/1/0561/4727/9946/products/FESTOON31.jpg', 'https://illume.com.mx/products/auxiliares-interiores', 'Faros auxiliares', true),
  ('6894761115722', 'Focos Led Illume Premium 55 Watts', 'Kit de luces LED ILLUME Premium 55 Watts se eleva a un nivel superior con una proyección de luz más brillante, uniforme y durabilidad mejorada, integra un Módulo LED CSP grado automotriz de alta potencia, obtendrás mayor visibilidad que con tus focos de halógeno actuales (hasta 200%). Su estructura de aluminio con difusor y ventilador garantiza la temperatura óptima para la durabilidad del LED, ya', 750, 'https://cdn.shopify.com/s/files/1/0561/4727/9946/files/5202.jpg', 'https://illume.com.mx/products/focos-led-illume-premium-lit', 'Kits LED', true),
  ('6894769635402', 'Focos Led Illume Plus', 'Kit de luces LED ILLUME PLUS 4 CARAS ofrece proyección de luz más brillante a 360 grados y durabilidad mejorada, integra un Módulo LED CSP grado automotriz de alta potencia, obtendrás mayor visibilidad que con tus focos de halógeno actuales (hasta 150%). Su estructura de aluminio con difusor y ventilador garantiza la temperatura óptima para la durabilidad del LED, además su instalación ahora es ma', 500, 'https://cdn.shopify.com/s/files/1/0561/4727/9946/products/Plus4caras.jpg', 'https://illume.com.mx/products/focos-led-illume-plu', 'Kits LED', true),
  ('6894765965386', 'Focos Led Illume Basic', 'Kit de luces LED ILLUME BASIC 4.0 proyección de luz más brillante, uniforme y durabilidad mejorada, integra un Módulo LED CSP grado automotriz de alta potencia, obtendrás mayor visibilidad que con tus focos de halógeno actuales (hasta 150%). Su estructura de aluminio con difusor y ventilador garantiza la temperatura óptima para la durabilidad del LED, además su instalación ahora es mas sencilla po', 550, 'https://cdn.shopify.com/s/files/1/0561/4727/9946/products/BASIC4.0.jpg', 'https://illume.com.mx/products/focos-led-illume', 'Kits LED', true),
  ('6894823440458', 'Focos Led Illume Exclusive 70W', 'Kit de luces LED ILLUME EXCLUSIVE se eleva a un nivel superior con una proyección de luz más brillante, uniforme y duradera mejorada, integra un Módulo LED CSP grado automotriz de alta potencia, obtendrás mayor visibilidad que con tus focos de halógeno actuales (hasta 300% ). Su estructura de aluminio con difusor y ventilador garantiza la temperatura óptima para la durabilidad del LED, ya que inte', 1299, 'https://cdn.shopify.com/s/files/1/0561/4727/9946/products/Exclusive.jpg', 'https://illume.com.mx/products/bulbos-led-illume-exclusiv', 'Kits LED', true),
  ('6894774812746', 'Focos Led Illume Bi Color', 'Kit de luces LED ILLUME BI COLOR se eleva a un nivel superior con una proyección de luz más brillante, uniforme y durabilidad mejorada, integra un Módulo LED CSP grado automotriz de alta potencia con su característica particular para cambiar su color a 2 tonalidades diferentes, Yellow extreme, y Blanco frio, obtendrás mayor visibilidad que con tus focos de halógeno actuales (hasta 150%) ideal para', 650, 'https://cdn.shopify.com/s/files/1/0561/4727/9946/products/Dualcolor.jpg', 'https://illume.com.mx/products/focos-led-illume-bi-colo', 'Kits LED', false),
  ('6894780809290', 'Focos Led H4 Lupa Proyectores', 'Kit de luces LED ILLUME Premium H4 Projector Lens se eleva a un nivel superior con una proyección de luz más brillante, corte de luz perfectamente afiliado y definido y durabilidad mejorada, integra un Módulo LED CSP grado automotriz de alta potencia, obtendrás mayor visibilidad que con tus focos de halógeno actuales (hasta 200%). Su estructura de aluminio con difusor y ventilador garantiza la tem', 1199, 'https://cdn.shopify.com/s/files/1/0561/4727/9946/files/4_f904ef54-5453-4658-a5b5-d693c754802b.jpg', 'https://illume.com.mx/products/focos-led-h4-lupa-proyectore', 'Lupas proyector', true)
) as v(source_id, name, description, price, image_url, external_url, category, active)
cross join (select id from public.providers where name = 'Illume') as p
on conflict (provider_id, source_id) where source_id is not null
do update set
  name          = excluded.name,
  description   = excluded.description,
  price         = excluded.price,
  image_url     = excluded.image_url,
  external_url  = excluded.external_url,
  category      = excluded.category,
  stock         = excluded.stock,
  active        = excluded.active;

-- 3. Fuentes del catalogo ------------------------------------------------------------------
insert into public.provider_catalog_sources
  (provider_id, url, platform, seller_id_or_store, product_count, status, last_synced_at, error_message)
select p.id, v.url, v.platform, v.seller, v.product_count, v.status, v.last_synced_at, v.error_message
from (values
  ('https://illume.com.mx', 'web', 'illume-com-mx.myshopify.com', 82, 'ok', now(), null::text),
  ('https://www.mercadolibre.com.mx/tienda/illume', 'mercadolibre', 'illume', 0, 'pendiente', null::timestamptz,
   'Requiere API oficial de MercadoLibre: el listado completo y las fichas exigen verificacion de cuenta.')
) as v(url, platform, seller, product_count, status, last_synced_at, error_message)
cross join (select id from public.providers where name = 'Illume') as p
on conflict (provider_id, url)
do update set
  platform           = excluded.platform,
  seller_id_or_store = excluded.seller_id_or_store,
  product_count      = excluded.product_count,
  status             = excluded.status,
  last_synced_at     = excluded.last_synced_at,
  error_message      = excluded.error_message;
